// ============================================================
// Wallet & Provider Service
// ============================================================
class WalletService {
  constructor() {
    this.provider = null;
    this.wallet = null;
    this.initialized = false;
  }

  initialize() {
    if (this.initialized) return;

    if (!CONFIG.PRIVATE_KEY) {
      throw new Error(
        'ETH_PRIVATE_KEY environment variable is not set. ' +
        'Please create a .env file with your private key.'
      );
    }

    // Validate private key format
    const keyRegex = /^(0x)?[0-9a-fA-F]{64}$/;
    if (!keyRegex.test(CONFIG.PRIVATE_KEY)) {
      throw new Error('Invalid private key format.');
    }

    this.provider = new ethers.JsonRpcProvider(CONFIG.RPC_URL, CONFIG.CHAIN_ID);
    this.wallet = new ethers.Wallet(CONFIG.PRIVATE_KEY, this.provider);
    this.initialized = true;

    console.log(`Wallet initialized. Address: ${this.wallet.address}`);
    console.log(`Connected to RPC: ${CONFIG.RPC_URL}`);
    console.log(`Chain ID: ${CONFIG.CHAIN_ID}`);
  }

  getProvider() {
    this.ensureInitialized();
    return this.provider;
  }

  getWallet() {
    this.ensureInitialized();
    return this.wallet;
  }

  getAddress() {
    this.ensureInitialized();
    return this.wallet.address;
  }

  ensureInitialized() {
    if (!this.initialized) {
      this.initialize();
    }
  }
}

// ============================================================
// Transaction Service
// ============================================================
class TransactionService {
  constructor(walletService) {
    this.walletService = walletService;
  }

  // Get current wallet ETH balance
  async getBalance() {
    const provider = this.walletService.getProvider();
    const address = this.walletService.getAddress();
    const balance = await provider.getBalance(address);
    return {
      address,
      balanceWei: balance.toString(),
      balanceEth: ethers.formatEther(balance),
    };
  }

  // Get ETH balance of any address
  async getBalanceOf(address) {
    if (!ethers.isAddress(address)) {
      throw new Error(`Invalid Ethereum address: ${address}`);
    }
    const provider = this.walletService.getProvider();
    const balance = await provider.getBalance(address);
    return {
      address,
      balanceWei: balance.toString(),
      balanceEth: ethers.formatEther(balance),
    };
  }

  // Send ETH to an address
  async sendETH(toAddress, amountInEth, options = {}) {
    if (!ethers.isAddress(toAddress)) {
      throw new Error(`Invalid recipient address: ${toAddress}`);
    }

    const amountWei = ethers.parseEther(amountInEth.toString());
    if (amountWei <= 0n) {
      throw new Error('Amount must be greater than 0');
    }

    const wallet = this.walletService.getWallet();

    // Check balance before sending
    const balance = await this.walletService.getProvider().getBalance(wallet.address);
    if (balance < amountWei) {
      throw new Error(
        `Insufficient balance. Have: ${ethers.formatEther(balance)} ETH, ` +
        `Need: ${amountInEth} ETH`
      );
    }

    const tx = {
      to: toAddress,
      value: amountWei,
      gasLimit: options.gasLimit || CONFIG.GAS_LIMIT_ETH_TRANSFER,
    };

    // Use EIP-1559 fee structure if supported
    if (options.maxFeePerGas) {
      tx.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
      tx.maxPriorityFeePerGas = ethers.parseUnits(
        (options.maxPriorityFeePerGas || CONFIG.MAX_PRIORITY_FEE_GWEI).toString(),
        'gwei'
      );
    } else if (options.gasPrice) {
      tx.gasPrice = ethers.parseUnits(options.gasPrice.toString(), 'gwei');
    }

    // Optional nonce override
    if (options.nonce !== undefined) {
      tx.nonce = options.nonce;
    }

    console.log(`Sending ${amountInEth} ETH to ${toAddress}...`);

    const txResponse = await wallet.sendTransaction(tx);
    console.log(`Transaction sent. Hash: ${txResponse.hash}`);

    // Wait for confirmation
    const confirmations = options.confirmations || 1;
    console.log(`Waiting for ${confirmations} confirmation(s)...`);
    const receipt = await txResponse.wait(confirmations);

    console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

    return {
      hash: txResponse.hash,
      from: receipt.from,
      to: receipt.to,
      value: amountInEth,
      gasUsed: receipt.gasUsed.toString(),
      effectiveGasPrice: receipt.gasPrice ? ethers.formatUnits(receipt.gasPrice, 'gwei') + ' gwei' : 'N/A',
      blockNumber: receipt.blockNumber,
      status: receipt.status === 1 ? 'success' : 'failed',
    };
  }

  // Get transaction receipt
  async getTransactionReceipt(txHash) {
    const provider = this.walletService.getProvider();
    const receipt = await provider.getTransactionReceipt(txHash);
    if (!receipt) {
      return { status: 'pending', hash: txHash };
    }
    return {
      hash: receipt.hash,
      from: receipt.from,
      to: receipt.to,
      gasUsed: receipt.gasUsed.toString(),
      blockNumber: receipt.blockNumber,
      status: receipt.status === 1 ? 'success' : 'failed',
      logs: receipt.logs.length,
    };
  }

  // Get current gas price estimates
  async getGasEstimates() {
    const provider = this.walletService.getProvider();
    const feeData = await provider.getFeeData();
    return {
      gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : 'N/A',
      maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei' : 'N/A',
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas
        ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei'
        : 'N/A',
    };
  }

  // Get current nonce for the wallet
  async getNonce() {
    const provider = this.walletService.getProvider();
    const address = this.walletService.getAddress();
    const nonce = await provider.getTransactionCount(address, 'latest');
    const pendingNonce = await provider.getTransactionCount(address, 'pending');
    return { address, nonce, pendingNonce };
  }

  // Get block information
  async getBlock(blockNumberOrHash) {
    const provider = this.walletService.getProvider();
    const block = await provider.getBlock(blockNumberOrHash || 'latest');
    return {
      number: block.number,
      hash: block.hash,
      timestamp: block.timestamp,
      date: new Date(block.timestamp * 1000).toISOString(),
      transactions: block.transactions.length,
      gasUsed: block.gasUsed.toString(),
      gasLimit: block.gasLimit.toString(),
      baseFeePerGas: block.baseFeePerGas ? ethers.formatUnits(block.baseFeePerGas, 'gwei') + ' gwei' : 'N/A',
    };
  }
}

